33	struct StandardAttention : AttentionVariantBase {
34	  float sm_scale_log2;
35	  // Per-tensor symmetric-quantization scales for the FP8 KV path. Both 1.0 on
36	  // the BF16/FP16 path so they are no-ops there.
37	  float ckv_scale;
38	  float kpe_scale;
39	
40	  PROFILER_CLOSURE_PARAMS_DECL
41	
42	  template <typename Params>
43	  __device__ __host__ StandardAttention(const Params& params, uint32_t batch_idx,
44	                                        uint8_t* smem_ptr) {
45	    sm_scale_log2 = params.sm_scale * math::log2e;
46	    ckv_scale = params.ckv_scale;
47	    kpe_scale = params.kpe_scale;
48	  }
49	};
