51	template <uint32_t NUM_STAGES, uint32_t CTA_TILE_Q, uint32_t CTA_TILE_KV, uint32_t HEAD_DIM_CKV,
52	          uint32_t HEAD_DIM_KPE, typename DTypeQ, typename DTypeKV, typename DTypeO>
53	struct SharedStorageQKVO {
54	  union {
55	    struct {
56	      alignas(16) DTypeQ q_smem_nope[CTA_TILE_Q * HEAD_DIM_CKV];
57	      alignas(16) DTypeQ q_smem_pe[CTA_TILE_Q * HEAD_DIM_KPE];
58	      alignas(16) DTypeKV ckv_smem[NUM_STAGES][CTA_TILE_KV * HEAD_DIM_CKV];
59	      alignas(16) DTypeKV
60	          kpe_p_smem[NUM_STAGES]
61	                    [CTA_TILE_KV * (HEAD_DIM_KPE > CTA_TILE_Q ? HEAD_DIM_KPE : CTA_TILE_Q)];
62	      union {
63	        alignas(16) float m_wg[2][CTA_TILE_Q];  // cross warpgroup synchronization
64	        alignas(16) float d_wg[2][CTA_TILE_Q];  // cross warpgroup synchronization
65	      };
66	    };
67	    alignas(16) DTypeO o_smem[CTA_TILE_Q * HEAD_DIM_CKV];
68	  };
69	};
