71	template <bool CAUSAL_, uint32_t NUM_STAGES_, bool QK_SHARD_, uint32_t HEAD_DIM_CKV_,
72	          uint32_t HEAD_DIM_KPE_, uint32_t CTA_TILE_Q_, uint32_t CTA_TILE_KV_, typename DTypeQ_,
73	          typename DTypeKV_, typename DTypeO_, typename IdType_>
74	struct KernelTraits {
75	  static constexpr bool CAUSAL = CAUSAL_;
76	  static constexpr uint32_t NUM_STAGES = NUM_STAGES_;
77	  // NOTE(Zihao): whether to shard Q*K computation across warpgroups
78	  // if true, each warpgroup will compute a subset of Q*K (sharded on the KV dimension)
79	  // if false, each warpgroup will compute the full Q*K, which is duplicated across warpgroups
80	  static constexpr bool QK_SHARD = QK_SHARD_;
81	  static constexpr uint32_t NUM_MMA_KV = CTA_TILE_KV_ / 16;
82	  static constexpr uint32_t HEAD_DIM_CKV = HEAD_DIM_CKV_;
83	  static constexpr uint32_t HEAD_DIM_KPE = HEAD_DIM_KPE_;
84	  static constexpr uint32_t HEAD_DIM_ALL = HEAD_DIM_CKV + HEAD_DIM_KPE;
85	  static constexpr uint32_t NUM_MMA_D_CKV = HEAD_DIM_CKV / 16;
86	  static constexpr uint32_t NUM_MMA_D_KPE = HEAD_DIM_KPE / 16;
87	  static constexpr uint32_t NUM_THREADS = 256;
88	  static constexpr uint32_t CTA_TILE_Q = CTA_TILE_Q_;
89	  static constexpr uint32_t CTA_TILE_KV = CTA_TILE_KV_;
90	
91	  static constexpr SwizzleMode SWIZZLE_MODE_Q_NOPE = SwizzleMode::k128B;
92	  static constexpr SwizzleMode SWIZZLE_MODE_Q_PE = SwizzleMode::k128B;
93	  static constexpr SwizzleMode SWIZZLE_MODE_CKV = SwizzleMode::k128B;
94	  static constexpr SwizzleMode SWIZZLE_MODE_KPE = SwizzleMode::k128B;
95	  static constexpr SwizzleMode SWIZZLE_MODE_P =
96	      CTA_TILE_KV >= 64 ? SwizzleMode::k128B : SwizzleMode::k64B;
97	  static constexpr SwizzleMode SWIZZLE_MODE_O = SwizzleMode::k128B;
98	  static constexpr uint32_t UPCAST_STRIDE_Q_NOPE = HEAD_DIM_CKV / upcast_size<DTypeQ_>();
99	  static constexpr uint32_t UPCAST_STRIDE_Q_PE = HEAD_DIM_KPE / upcast_size<DTypeQ_>();
100	  static constexpr uint32_t UPCAST_STRIDE_CKV = HEAD_DIM_CKV / upcast_size<DTypeKV_>();
101	  static constexpr uint32_t UPCAST_STRIDE_KPE = HEAD_DIM_KPE / upcast_size<DTypeKV_>();
102	  static constexpr uint32_t UPCAST_STRIDE_FINAL_O = HEAD_DIM_CKV / upcast_size<DTypeO_>();
103	  static constexpr uint32_t UPCAST_STRIDE_P = CTA_TILE_KV / upcast_size<DTypeKV_>();
104	
105	  using DTypeQ = DTypeQ_;
106	  using DTypeKV = DTypeKV_;
107	  using DTypeO = DTypeO_;
108	  using IdType = IdType_;
109	  using DTypeQKAccum = float;
110	
111	  using SharedStorage = SharedStorageQKVO<NUM_STAGES, CTA_TILE_Q, CTA_TILE_KV, HEAD_DIM_CKV,
112	                                          HEAD_DIM_KPE, DTypeQ, DTypeKV, DTypeO>;
113	  using AttentionVariant = StandardAttention;
114	
115	  static constexpr DTypeQKAccum MaskFillValue = -math::inf;
116	};
