118	template <typename KTraits>
119	__device__ __forceinline__ void init_states_(float (*o_frag)[8], typename KTraits::DTypeQKAccum* m,
120	                                             float* d) {
121	#pragma unroll
122	  for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_CKV / 2; ++mma_d) {
123	#pragma unroll
124	    for (uint32_t reg_id = 0; reg_id < 8; ++reg_id) {
125	      o_frag[mma_d][reg_id] = 0.f;
126	    }
127	  }
128	
129	#pragma unroll
130	  for (uint32_t j = 0; j < 2; ++j) {
131	    m[j] = typename KTraits::DTypeQKAccum(-math::inf);
132	    d[j] = 1.f;
133	  }
134	}
