136	template <typename KTraits>
137	__device__ __forceinline__ void load_q(
138	    typename KTraits::SharedStorage* smem_storage, typename KTraits::DTypeQ* q_nope,
139	    typename KTraits::DTypeQ* q_pe, const uint32_t q_nope_stride_n, const uint32_t q_nope_stride_h,
140	    const uint32_t q_pe_stride_n, const uint32_t q_pe_stride_h, const uint32_t q_len,
141	    const uint32_t packed_offset, const uint_fastdiv& num_heads) {
142	  using DTypeQ = typename KTraits::DTypeQ;
143	  constexpr uint32_t UPCAST_STRIDE_Q_NOPE = KTraits::UPCAST_STRIDE_Q_NOPE;
144	  constexpr uint32_t UPCAST_STRIDE_Q_PE = KTraits::UPCAST_STRIDE_Q_PE;
145	  constexpr uint32_t NUM_MMA_D_CKV = KTraits::NUM_MMA_D_CKV;
146	  constexpr uint32_t NUM_MMA_D_KPE = KTraits::NUM_MMA_D_KPE;
147	  const uint32_t lane_idx = threadIdx.x;
148	  const uint32_t warpgroup_idx = threadIdx.z;
149	  const uint32_t warp_idx_in_wg = threadIdx.y;
150	
151	  smem_t<KTraits::SWIZZLE_MODE_Q_NOPE> q_smem_nope(smem_storage->q_smem_nope);
152	  smem_t<KTraits::SWIZZLE_MODE_Q_PE> q_smem_pe(smem_storage->q_smem_pe);
153	
154	#pragma unroll
155	  for (uint32_t mma_q = 0; mma_q < 2; ++mma_q) {
156	    uint32_t q, r;
157	    num_heads.divmod(
158	        packed_offset + lane_idx / 8 + (warpgroup_idx + mma_q * 2) * 16 + warp_idx_in_wg * 4, q, r);
159	    DTypeQ* q_nope_ptr =
160	        q_nope + q * q_nope_stride_n + r * q_nope_stride_h + (lane_idx % 8) * upcast_size<DTypeQ>();
161	    DTypeQ* q_pe_ptr =
162	        q_pe + q * q_pe_stride_n + r * q_pe_stride_h + (lane_idx % 8) * upcast_size<DTypeQ>();
163	#pragma unroll
164	    for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_CKV / 4; ++mma_d) {
165	      uint32_t q_smem_nope_offset_w =
166	          q_smem_nope.template get_permuted_offset<UPCAST_STRIDE_Q_NOPE>(
167	              32 * mma_q + warpgroup_idx * 16 + warp_idx_in_wg * 4 + lane_idx / 8,
168	              mma_d * 8 + lane_idx % 8);
169	      q_smem_nope.load_128b_async<SharedMemFillMode::kFillZero>(q_smem_nope_offset_w, q_nope_ptr,
170	                                                                q < q_len);
171	      q_nope_ptr += 8 * upcast_size<DTypeQ>();
172	    }
173	#pragma unroll
174	    for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_KPE / 4; ++mma_d) {
175	      uint32_t q_smem_pe_offset_w = q_smem_pe.template get_permuted_offset<UPCAST_STRIDE_Q_PE>(
176	          32 * mma_q + warpgroup_idx * 16 + warp_idx_in_wg * 4 + lane_idx / 8,
177	          mma_d * 8 + lane_idx % 8);
178	
179	      q_smem_pe.load_128b_async<SharedMemFillMode::kFillZero>(q_smem_pe_offset_w, q_pe_ptr,
180	                                                              q < q_len);
181	      q_pe_ptr += 8 * upcast_size<DTypeQ>();
182	    }
183	  }
184	}
