186	template <typename KTraits>
187	__device__ __forceinline__ void load_kv(
188	    typename KTraits::SharedStorage* smem_storage, typename KTraits::DTypeKV* ckv,
189	    typename KTraits::DTypeKV* kpe, typename KTraits::IdType* indices, const uint32_t ckv_stride_n,
190	    const uint32_t ckv_stride_page, const uint32_t kpe_stride_n, const uint32_t kpe_stride_page,
191	    const uint32_t packed_kv_bound, const uint32_t packed_block_iter_base,
192	    const uint_fastdiv& block_size, const uint32_t stage_idx) {
193	  using DTypeKV = typename KTraits::DTypeKV;
194	  constexpr uint32_t UPCAST_STRIDE_CKV = KTraits::UPCAST_STRIDE_CKV;
195	  constexpr uint32_t UPCAST_STRIDE_KPE = KTraits::UPCAST_STRIDE_KPE;
196	  constexpr uint32_t NUM_MMA_D_CKV = KTraits::NUM_MMA_D_CKV;
197	  constexpr uint32_t NUM_MMA_D_KPE = KTraits::NUM_MMA_D_KPE;
198	  const uint32_t lane_idx = threadIdx.x;
199	  const uint32_t warpgroup_idx = threadIdx.z;
200	  const uint32_t warp_idx_in_wg = threadIdx.y;
201	
202	  smem_t<KTraits::SWIZZLE_MODE_CKV> ckv_smem(smem_storage->ckv_smem[stage_idx]);
203	  smem_t<KTraits::SWIZZLE_MODE_KPE> kpe_smem(smem_storage->kpe_p_smem[stage_idx]);
204	
205	  if constexpr (KTraits::NUM_MMA_KV == 1) {
206	    if (warpgroup_idx == 0) {
207	      uint32_t q, r;
208	      uint32_t packed_block_iter = packed_block_iter_base + lane_idx / 8 + warp_idx_in_wg * 4;
209	      block_size.divmod(packed_block_iter, q, r);
210	
211	      // Cast page index to int64_t before multiplying to avoid overflow.
212	      DTypeKV* ckv_ptr =
213	          ckv +
214	          static_cast<int64_t>(packed_block_iter < packed_kv_bound ? indices[q] : 0) *
215	              ckv_stride_page +
216	          r * ckv_stride_n + (lane_idx % 8) * upcast_size<DTypeKV>();
217	      DTypeKV* kpe_ptr =
218	          kpe +
219	          static_cast<int64_t>(packed_block_iter < packed_kv_bound ? indices[q] : 0) *
220	              kpe_stride_page +
221	          r * kpe_stride_n + (lane_idx % 8) * upcast_size<DTypeKV>();
222	
223	#pragma unroll
224	      for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_CKV / 4; ++mma_d) {
225	        uint32_t ckv_smem_offset_w = ckv_smem.template get_permuted_offset<UPCAST_STRIDE_CKV>(
226	            warp_idx_in_wg * 4 + lane_idx / 8, 8 * mma_d + lane_idx % 8);
227	        ckv_smem.load_128b_async<SharedMemFillMode::kFillZero>(ckv_smem_offset_w, ckv_ptr,
228	                                                               packed_block_iter < packed_kv_bound);
229	        ckv_ptr += 8 * upcast_size<DTypeKV>();
230	      }
231	
232	#pragma unroll
233	      for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_KPE / 4; ++mma_d) {
234	        uint32_t kpe_smem_offset_w = kpe_smem.template get_permuted_offset<UPCAST_STRIDE_KPE>(
235	            warp_idx_in_wg * 4 + lane_idx / 8, 8 * mma_d + lane_idx % 8);
236	        kpe_smem.load_128b_async<SharedMemFillMode::kFillZero>(kpe_smem_offset_w, kpe_ptr,
237	                                                               packed_block_iter < packed_kv_bound);
238	        kpe_ptr += 8 * upcast_size<DTypeKV>();
239	      }
240	    }
241	  } else {
242	#pragma unroll
243	    for (uint32_t mma_kv = 0; mma_kv < KTraits::NUM_MMA_KV / 2; ++mma_kv) {
244	      uint32_t q, r;
245	      uint32_t packed_block_iter = packed_block_iter_base + lane_idx / 8 +
246	                                   (warpgroup_idx + mma_kv * 2) * 16 + warp_idx_in_wg * 4;
247	      block_size.divmod(packed_block_iter, q, r);
248	
249	      // See comment above: widen to int64_t to avoid 32-bit overflow when indices[q] is large.
250	      DTypeKV* ckv_ptr =
251	          ckv +
252	          static_cast<int64_t>(packed_block_iter < packed_kv_bound ? indices[q] : 0) *
253	              ckv_stride_page +
254	          r * ckv_stride_n + (lane_idx % 8) * upcast_size<DTypeKV>();
255	      DTypeKV* kpe_ptr =
256	          kpe +
257	          static_cast<int64_t>(packed_block_iter < packed_kv_bound ? indices[q] : 0) *
258	              kpe_stride_page +
259	          r * kpe_stride_n + (lane_idx % 8) * upcast_size<DTypeKV>();
260	
261	#pragma unroll
262	      for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_CKV / 4; ++mma_d) {
263	        uint32_t ckv_smem_offset_w = ckv_smem.template get_permuted_offset<UPCAST_STRIDE_CKV>(
264	            32 * mma_kv + warpgroup_idx * 16 + warp_idx_in_wg * 4 + lane_idx / 8,
265	            8 * mma_d + lane_idx % 8);
266	        ckv_smem.load_128b_async<SharedMemFillMode::kFillZero>(ckv_smem_offset_w, ckv_ptr,
267	                                                               packed_block_iter < packed_kv_bound);
268	        ckv_ptr += 8 * upcast_size<DTypeKV>();
269	      }
270	
271	#pragma unroll
272	      for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_KPE / 4; ++mma_d) {
273	        uint32_t kpe_smem_offset_w = kpe_smem.template get_permuted_offset<UPCAST_STRIDE_KPE>(
274	            32 * mma_kv + warpgroup_idx * 16 + warp_idx_in_wg * 4 + lane_idx / 8,
275	            8 * mma_d + lane_idx % 8);
276	        kpe_smem.load_128b_async<SharedMemFillMode::kFillZero>(kpe_smem_offset_w, kpe_ptr,
277	                                                               packed_block_iter < packed_kv_bound);
278	        kpe_ptr += 8 * upcast_size<DTypeKV>();
279	      }
280	    }
281	  }
282	}
283	
284	template <bool init, typename KTraits, uint32_t NUM_MMA_D_QK, uint32_t UPCAST_STRIDE_Q,
285	          uint32_t UPCAST_STRIDE_K, SwizzleMode SWIZZLE_MODE_Q, SwizzleMode SWIZZLE_MODE_KV>
286	__device__ __forceinline__ void compute_qk_(smem_t<SWIZZLE_MODE_Q> q_smem,
287	                                            smem_t<SWIZZLE_MODE_KV> k_smem,
288	                                            typename KTraits::DTypeQKAccum (*s_frag)[8]) {
289	  const uint32_t lane_idx = threadIdx.x, warpgroup_idx = threadIdx.z, warp_idx_in_wg = threadIdx.y;
290	  alignas(16) uint32_t q_frag[4], k_frag[4];
291	  // compute q*k^T
292	#pragma unroll
293	  for (uint32_t mma_d = 0; mma_d < NUM_MMA_D_QK; ++mma_d) {
294	    uint32_t q_smem_offset_r = q_smem.template get_permuted_offset<UPCAST_STRIDE_Q>(
295	        warp_idx_in_wg * 16 + lane_idx % 16, mma_d * 2 + lane_idx / 16);
296	    q_smem.ldmatrix_m8n8x4(q_smem_offset_r, q_frag);
297	
298	    if constexpr (KTraits::QK_SHARD) {
299	#pragma unroll
300	      for (uint32_t mma_kv = 0; mma_kv < KTraits::NUM_MMA_KV / 2; ++mma_kv) {
301	        uint32_t k_smem_offset_r = k_smem.template get_permuted_offset<UPCAST_STRIDE_K>(
302	            (warpgroup_idx * (KTraits::NUM_MMA_KV / 2) + mma_kv) * 16 + 8 * (lane_idx / 16) +
303	                lane_idx % 8,
304	            2 * mma_d + (lane_idx % 16) / 8);
305	
306	        k_smem.ldmatrix_m8n8x4(k_smem_offset_r, k_frag);
307	
308	        if (init && mma_d == 0) {
309	          mma::mma_sync_m16n16k16_row_col_f16f16f32<typename KTraits::DTypeQ, MMAMode::kInit>(
310	              s_frag[mma_kv], q_frag, k_frag);
311	        } else {
312	          mma::mma_sync_m16n16k16_row_col_f16f16f32<typename KTraits::DTypeQ>(s_frag[mma_kv],
313	                                                                              q_frag, k_frag);
314	        }
315	      }
316	    } else {
317	#pragma unroll
318	      for (uint32_t mma_kv = 0; mma_kv < KTraits::NUM_MMA_KV; ++mma_kv) {
319	        uint32_t k_smem_offset_r = k_smem.template get_permuted_offset<UPCAST_STRIDE_K>(
320	            mma_kv * 16 + 8 * (lane_idx / 16) + lane_idx % 8, 2 * mma_d + (lane_idx % 16) / 8);
321	
322	        k_smem.ldmatrix_m8n8x4(k_smem_offset_r, k_frag);
323	
324	        if (init && mma_d == 0) {
325	          mma::mma_sync_m16n16k16_row_col_f16f16f32<typename KTraits::DTypeQ, MMAMode::kInit>(
326	              s_frag[mma_kv], q_frag, k_frag);
327	        } else {
328	          mma::mma_sync_m16n16k16_row_col_f16f16f32<typename KTraits::DTypeQ>(s_frag[mma_kv],
329	                                                                              q_frag, k_frag);
330	        }
331	      }
332	    }
333	  }
334	}
