336	template <typename KTraits>
337	__device__ __forceinline__ void logits_mask_(const uint32_t qo_packed_idx_base,
338	                                             const uint32_t kv_idx_base, const uint32_t qo_len,
339	                                             const uint32_t kv_len, const uint32_t kv_end,
340	                                             const uint_fastdiv num_heads,
341	                                             typename KTraits::DTypeQKAccum (*s_frag)[8]) {
342	  const uint32_t lane_idx = threadIdx.x, warpgroup_idx = threadIdx.z, warp_idx_in_wg = threadIdx.y;
343	  constexpr uint32_t NUM_MMA_KV = KTraits::NUM_MMA_KV;
344	  using DTypeQKAccum = typename KTraits::DTypeQKAccum;
345	  uint32_t q[2];
346	#pragma unroll
347	  for (uint32_t j = 0; j < 2; ++j) {
348	    q[j] = (qo_packed_idx_base + warp_idx_in_wg * 16 + lane_idx / 4 + 8 * j) / num_heads;
349	  }
350	
351	  if constexpr (KTraits::QK_SHARD) {
352	#pragma unroll
353	    for (uint32_t mma_kv = 0; mma_kv < NUM_MMA_KV / 2; ++mma_kv) {
354	#pragma unroll
355	      for (uint32_t reg_id = 0; reg_id < 8; ++reg_id) {
356	        const uint32_t q_idx = q[(reg_id % 4) / 2],
357	                       kv_idx = kv_idx_base + warpgroup_idx * (NUM_MMA_KV / 2) * 16 + mma_kv * 16 +
358	                                2 * (lane_idx % 4) + 8 * (reg_id / 4) + reg_id % 2;
359	        const bool mask =
360	            (!(KTraits::CAUSAL ? (kv_idx + qo_len > kv_len + q_idx || (kv_idx >= kv_end))
361	                               : kv_idx >= kv_end));
362	        s_frag[mma_kv][reg_id] = (mask) ? s_frag[mma_kv][reg_id] : (KTraits::MaskFillValue);
363	      }
364	    }
365	  } else {
366	#pragma unroll
367	    for (uint32_t mma_kv = 0; mma_kv < NUM_MMA_KV; ++mma_kv) {
368	#pragma unroll
369	      for (uint32_t reg_id = 0; reg_id < 8; ++reg_id) {
370	        const uint32_t q_idx = q[(reg_id % 4) / 2], kv_idx = kv_idx_base + mma_kv * 16 +
371	                                                             2 * (lane_idx % 4) + 8 * (reg_id / 4) +
372	                                                             reg_id % 2;
373	        const bool mask =
374	            (!(KTraits::CAUSAL ? (kv_idx + qo_len > kv_len + q_idx || (kv_idx >= kv_end))
375	                               : kv_idx >= kv_end));
376	        s_frag[mma_kv][reg_id] = (mask) ? s_frag[mma_kv][reg_id] : (KTraits::MaskFillValue);
377	      }
378	    }
379	  }
380	}
