382	template <typename KTraits>
383	__device__ __forceinline__ void update_mdo_states_(typename KTraits::SharedStorage* smem_storage,
384	                                                   const uint32_t stage_idx,
385	                                                   typename KTraits::AttentionVariant variant,
386	                                                   typename KTraits::DTypeQKAccum (*s_frag)[8],
387	                                                   float (*o_frag)[8],
388	                                                   typename KTraits::DTypeQKAccum* m, float* d) {
389	  using DTypeQKAccum = typename KTraits::DTypeQKAccum;
390	  using AttentionVariant = typename KTraits::AttentionVariant;
391	  const float sm_scale = variant.sm_scale_log2;
392	  const uint32_t warpgroup_idx = threadIdx.z, lane_idx = threadIdx.x, warp_idx_in_wg = threadIdx.y;
393	  float m_prev[2];
394	  if constexpr (KTraits::QK_SHARD) {
395	#pragma unroll
396	    for (uint32_t j = 0; j < 2; ++j) {
397	      m_prev[j] = m[j];
398	#pragma unroll
399	      for (uint32_t mma_kv = 0; mma_kv < KTraits::NUM_MMA_KV / 2; ++mma_kv) {
400	        float m_local = max(max(s_frag[mma_kv][j * 2 + 0], s_frag[mma_kv][j * 2 + 1]),
401	                            max(s_frag[mma_kv][j * 2 + 4], s_frag[mma_kv][j * 2 + 5]));
402	        m[j] = max(m[j], m_local);
403	      }
404	      m[j] = max(m[j], math::shfl_xor_sync(m[j], 0x2));
405	      m[j] = max(m[j], math::shfl_xor_sync(m[j], 0x1));
406	      if (lane_idx % 4 == 0) {
407	        smem_storage->m_wg[warpgroup_idx][warp_idx_in_wg * 16 + j * 8 + lane_idx / 4] = m[j];
408	      }
409	    }
410	
411	    __syncthreads();
412	
413	#pragma unroll
414	    for (uint32_t j = 0; j < 2; ++j) {
415	      m[j] = max(smem_storage->m_wg[0][warp_idx_in_wg * 16 + j * 8 + lane_idx / 4],
416	                 smem_storage->m_wg[1][warp_idx_in_wg * 16 + j * 8 + lane_idx / 4]);
417	      float o_scale = math::ptx_exp2(m_prev[j] * sm_scale - m[j] * sm_scale);
418	      d[j] *= o_scale;
419	#pragma unroll
420	      for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_CKV / 2; ++mma_d) {
421	        o_frag[mma_d][j * 2 + 0] *= o_scale;
422	        o_frag[mma_d][j * 2 + 1] *= o_scale;
423	        o_frag[mma_d][j * 2 + 4] *= o_scale;
424	        o_frag[mma_d][j * 2 + 5] *= o_scale;
425	      }
426	#pragma unroll
427	      for (uint32_t mma_kv = 0; mma_kv < KTraits::NUM_MMA_KV / 2; ++mma_kv) {
428	        s_frag[mma_kv][j * 2 + 0] =
429	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 0] * sm_scale - m[j] * sm_scale);
430	        s_frag[mma_kv][j * 2 + 1] =
431	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 1] * sm_scale - m[j] * sm_scale);
432	        s_frag[mma_kv][j * 2 + 4] =
433	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 4] * sm_scale - m[j] * sm_scale);
434	        s_frag[mma_kv][j * 2 + 5] =
435	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 5] * sm_scale - m[j] * sm_scale);
436	      }
437	    }
438	  } else {
439	#pragma unroll
440	    for (uint32_t j = 0; j < 2; ++j) {
441	      m_prev[j] = m[j];
442	#pragma unroll
443	      for (uint32_t mma_kv = 0; mma_kv < KTraits::NUM_MMA_KV; ++mma_kv) {
444	        float m_local = max(max(s_frag[mma_kv][j * 2 + 0], s_frag[mma_kv][j * 2 + 1]),
445	                            max(s_frag[mma_kv][j * 2 + 4], s_frag[mma_kv][j * 2 + 5]));
446	        m[j] = max(m[j], m_local);
447	      }
448	      m[j] = max(m[j], math::shfl_xor_sync(m[j], 0x2));
449	      m[j] = max(m[j], math::shfl_xor_sync(m[j], 0x1));
450	    }
451	
452	#pragma unroll
453	    for (uint32_t j = 0; j < 2; ++j) {
454	      float o_scale = math::ptx_exp2(m_prev[j] * sm_scale - m[j] * sm_scale);
455	      d[j] *= o_scale;
456	#pragma unroll
457	      for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_CKV / 2; ++mma_d) {
458	        o_frag[mma_d][j * 2 + 0] *= o_scale;
459	        o_frag[mma_d][j * 2 + 1] *= o_scale;
460	        o_frag[mma_d][j * 2 + 4] *= o_scale;
461	        o_frag[mma_d][j * 2 + 5] *= o_scale;
462	      }
463	#pragma unroll
464	      for (uint32_t mma_kv = 0; mma_kv < KTraits::NUM_MMA_KV; ++mma_kv) {
465	        s_frag[mma_kv][j * 2 + 0] =
466	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 0] * sm_scale - m[j] * sm_scale);
467	        s_frag[mma_kv][j * 2 + 1] =
468	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 1] * sm_scale - m[j] * sm_scale);
469	        s_frag[mma_kv][j * 2 + 4] =
470	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 4] * sm_scale - m[j] * sm_scale);
471	        s_frag[mma_kv][j * 2 + 5] =
472	            math::ptx_exp2(s_frag[mma_kv][j * 2 + 5] * sm_scale - m[j] * sm_scale);
473	      }
474	    }
475	  }
476	}
