478	template <typename KTraits>
479	__device__ __forceinline__ void compute_mla_qk(typename KTraits::SharedStorage* smem_storage,
480	                                               const uint32_t stage_idx,
481	                                               typename KTraits::DTypeQKAccum (*s_frag)[8]) {
482	  constexpr uint32_t UPCAST_STRIDE_Q_NOPE = KTraits::UPCAST_STRIDE_Q_NOPE;
483	  constexpr uint32_t UPCAST_STRIDE_Q_PE = KTraits::UPCAST_STRIDE_Q_PE;
484	  constexpr uint32_t UPCAST_STRIDE_CKV = KTraits::UPCAST_STRIDE_CKV;
485	  constexpr uint32_t UPCAST_STRIDE_KPE = KTraits::UPCAST_STRIDE_KPE;
486	  constexpr uint32_t NUM_MMA_KV = KTraits::NUM_MMA_KV;
487	  smem_t<KTraits::SWIZZLE_MODE_Q_NOPE> q_smem_nope(smem_storage->q_smem_nope);
488	  smem_t<KTraits::SWIZZLE_MODE_Q_PE> q_smem_pe(smem_storage->q_smem_pe);
489	  smem_t<KTraits::SWIZZLE_MODE_CKV> ckv_smem(smem_storage->ckv_smem[stage_idx]);
490	  smem_t<KTraits::SWIZZLE_MODE_KPE> kpe_smem(smem_storage->kpe_p_smem[stage_idx]);
491	  const uint32_t lane_idx = threadIdx.x, warpgroup_idx = threadIdx.z, warp_idx_in_wg = threadIdx.y;
492	  compute_qk_</*init=*/true, KTraits, KTraits::NUM_MMA_D_KPE, KTraits::UPCAST_STRIDE_Q_PE,
493	              KTraits::UPCAST_STRIDE_KPE>(q_smem_pe, kpe_smem, s_frag);
494	  compute_qk_</*init=*/false, KTraits, KTraits::NUM_MMA_D_CKV, KTraits::UPCAST_STRIDE_Q_NOPE,
495	              KTraits::UPCAST_STRIDE_CKV>(q_smem_nope, ckv_smem, s_frag);
496	}
