498	template <typename KTraits>
499	__device__ __forceinline__ void compute_mla_pv(typename KTraits::SharedStorage* smem_storage,
500	                                               const uint32_t stage_idx,
501	                                               typename KTraits::DTypeQKAccum (*s_frag)[8],
502	                                               typename KTraits::DTypeQKAccum* d,
503	                                               float (*o_frag)[8]) {
504	  const uint32_t lane_idx = threadIdx.x, warpgroup_idx = threadIdx.z, warp_idx_in_wg = threadIdx.y;
505	  constexpr uint32_t NUM_MMA_KV = KTraits::NUM_MMA_KV;
506	  constexpr uint32_t NUM_MMA_D_CKV = KTraits::NUM_MMA_D_CKV;
507	  constexpr uint32_t UPCAST_STRIDE_CKV = KTraits::UPCAST_STRIDE_CKV;
508	  smem_t<KTraits::SWIZZLE_MODE_CKV> ckv_smem(smem_storage->ckv_smem[stage_idx]);
509	  uint32_t ckv_smem_offset_r = ckv_smem.template get_permuted_offset<UPCAST_STRIDE_CKV>(
510	      lane_idx % 16, warpgroup_idx * NUM_MMA_D_CKV + lane_idx / 16);
511	  if constexpr (KTraits::QK_SHARD) {
512	    // shard s_frag computation on KV dimension across warpgroups, need allgather
513	    alignas(16) typename KTraits::DTypeKV p_f16[NUM_MMA_KV / 2][8];
514	#pragma unroll
515	    for (uint32_t mma_kv = 0; mma_kv < NUM_MMA_KV / 2; ++mma_kv) {
516	      vec_cast<typename KTraits::DTypeKV, float>::cast<8>(p_f16[mma_kv], s_frag[mma_kv]);
517	      mma::m16k16_rowsum_f16f16f32(d, p_f16[mma_kv]);
518	    }
519	
520	    __syncthreads();
521	    smem_t<KTraits::SWIZZLE_MODE_P> p_smem(smem_storage->kpe_p_smem[stage_idx]);
522	    constexpr uint32_t UPCAST_STRIDE_P = KTraits::UPCAST_STRIDE_P;
523	#pragma unroll
524	    for (uint32_t mma_kv = 0; mma_kv < NUM_MMA_KV / 2; ++mma_kv) {
525	#ifdef FLASHINFER_STMATRIX_M8N8X4_ENABLED
526	      uint32_t p_smem_offset_w = p_smem.template get_permuted_offset<UPCAST_STRIDE_P>(
527	          warp_idx_in_wg * 16 + lane_idx % 16,
528	          warpgroup_idx * NUM_MMA_KV + mma_kv * 2 + lane_idx / 16);
529	      p_smem.stmatrix_m8n8x4(p_smem_offset_w, (uint32_t*)p_f16[mma_kv]);
530	#else
531	      uint32_t p_smem_offset_w = p_smem.template get_permuted_offset<UPCAST_STRIDE_P>(
532	          warp_idx_in_wg * 16 + lane_idx / 4, warpgroup_idx * NUM_MMA_KV + mma_kv * 2);
533	      ((uint32_t*)(p_smem.base + p_smem_offset_w))[lane_idx % 4] = *(uint32_t*)&p_f16[mma_kv][0];
534	      ((uint32_t*)(p_smem.base + p_smem_offset_w + 8 * UPCAST_STRIDE_P))[lane_idx % 4] =
535	          *(uint32_t*)&p_f16[mma_kv][2];
536	      ((uint32_t*)(p_smem.base + (p_smem_offset_w ^ 0x1)))[lane_idx % 4] =
537	          *(uint32_t*)&p_f16[mma_kv][4];
538	      ((uint32_t*)(p_smem.base + (p_smem_offset_w ^ 0x1) + 8 * UPCAST_STRIDE_P))[lane_idx % 4] =
539	          *(uint32_t*)&p_f16[mma_kv][6];
540	#endif
541	    }
542	    uint32_t p_smem_offset_r = p_smem.template get_permuted_offset<UPCAST_STRIDE_P>(
543	        warp_idx_in_wg * 16 + lane_idx % 16, lane_idx / 16);
544	
545	    // wait for p_smem to be filled
546	    __syncthreads();
547	
548	#pragma unroll
549	    for (uint32_t mma_kv = 0; mma_kv < NUM_MMA_KV; ++mma_kv) {
550	      uint32_t p_frag[4];
551	      p_smem.ldmatrix_m8n8x4(p_smem_offset_r, p_frag);
552	      p_smem_offset_r = p_smem.template advance_offset_by_column<2>(p_smem_offset_r, mma_kv);
553	
554	#pragma unroll
555	      for (uint32_t mma_d = 0; mma_d < NUM_MMA_D_CKV / 2; ++mma_d) {
556	        uint32_t v_frag[4];
557	        ckv_smem.ldmatrix_m8n8x4_trans(ckv_smem_offset_r, v_frag);
558	        mma::mma_sync_m16n16k16_row_col_f16f16f32<typename KTraits::DTypeKV>(o_frag[mma_d], p_frag,
559	                                                                             v_frag);
560	        ckv_smem_offset_r = ckv_smem.template advance_offset_by_column<2>(ckv_smem_offset_r, mma_d);
561	      }
562	      ckv_smem_offset_r =
563	          ckv_smem.template advance_offset_by_row<16, UPCAST_STRIDE_CKV>(ckv_smem_offset_r) -
564	          NUM_MMA_D_CKV;
565	    }
566	  } else {
567	    // no need to store p_smem because all warpgroups are working on the same p
568	    alignas(16) typename KTraits::DTypeKV p_f16[NUM_MMA_KV][8];
569	#pragma unroll
570	    for (uint32_t mma_kv = 0; mma_kv < NUM_MMA_KV; ++mma_kv) {
571	      vec_cast<typename KTraits::DTypeKV, float>::cast<8>(p_f16[mma_kv], s_frag[mma_kv]);
572	      mma::m16k16_rowsum_f16f16f32(d, p_f16[mma_kv]);
573	    }
574	#pragma unroll
575	    for (uint32_t mma_kv = 0; mma_kv < NUM_MMA_KV; ++mma_kv) {
576	#pragma unroll
577	      for (uint32_t mma_d = 0; mma_d < NUM_MMA_D_CKV / 2; ++mma_d) {
578	        uint32_t v_frag[4];
579	        ckv_smem.ldmatrix_m8n8x4_trans(ckv_smem_offset_r, v_frag);
580	        mma::mma_sync_m16n16k16_row_col_f16f16f32<typename KTraits::DTypeKV>(
581	            o_frag[mma_d], (uint32_t*)p_f16[mma_kv], v_frag);
582	        ckv_smem_offset_r = ckv_smem.template advance_offset_by_column<2>(ckv_smem_offset_r, mma_d);
583	      }
584	      ckv_smem_offset_r =
585	          ckv_smem.template advance_offset_by_row<16, UPCAST_STRIDE_CKV>(ckv_smem_offset_r) -
586	          NUM_MMA_D_CKV;
587	    }
588	  }
589	}
