591	template <typename KTraits>
592	__device__ __forceinline__ void normalize_d_(typename KTraits::SharedStorage* smem_storage,
593	                                             const uint32_t stage_idx, float (*o_frag)[8],
594	                                             typename KTraits::DTypeQKAccum* m, float* d) {
595	  const uint32_t warpgroup_idx = threadIdx.z, lane_idx = threadIdx.x, warp_idx_in_wg = threadIdx.y;
596	  if constexpr (KTraits::QK_SHARD) {
597	#pragma unroll
598	    for (uint32_t j = 0; j < 2; ++j) {
599	      if (lane_idx % 4 == 0) {
600	        smem_storage->d_wg[warpgroup_idx][warp_idx_in_wg * 16 + j * 8 + lane_idx / 4] = d[j];
601	      }
602	    }
603	    __syncthreads();
604	#pragma unroll
605	    for (uint32_t j = 0; j < 2; ++j) {
606	      d[j] = smem_storage->d_wg[0][warp_idx_in_wg * 16 + j * 8 + lane_idx / 4] +
607	             smem_storage->d_wg[1][warp_idx_in_wg * 16 + j * 8 + lane_idx / 4];
608	    }
609	  }
610	
611	  float d_rcp[2];
612	  // compute reciprocal of d
613	#pragma unroll
614	  for (uint32_t j = 0; j < 2; ++j) {
615	    d_rcp[j] = (m[j] != typename KTraits::DTypeQKAccum(-math::inf)) ? math::ptx_rcp(d[j]) : 0.f;
616	  }
617	
618	#pragma unroll
619	  for (uint32_t mma_d = 0; mma_d < KTraits::NUM_MMA_D_CKV / 2; ++mma_d) {
620	#pragma unroll
621	    for (uint32_t reg_id = 0; reg_id < 8; ++reg_id) {
622	      o_frag[mma_d][reg_id] = o_frag[mma_d][reg_id] * d_rcp[(reg_id % 4) / 2];
623	    }
624	  }
625	}
