627	template <typename KTraits>
628	__device__ __forceinline__ void finalize_m_(typename KTraits::AttentionVariant variant,
629	                                            typename KTraits::DTypeQKAccum* m) {
630	  if constexpr (variant.use_softmax) {
631	#pragma unroll
632	    for (uint32_t j = 0; j < 2; ++j) {
633	      if (m[j] != typename KTraits::DTypeQKAccum(-math::inf)) {
634	        m[j] *= variant.sm_scale_log2;
635	      }
636	    }
637	  }
638	}
