640	template <typename KTraits>
641	__device__ void DevicePersistentMergeStates(
642	    typename KTraits::IdType* merge_packed_offset_start,
643	    typename KTraits::IdType* merge_packed_offset_end,
644	    typename KTraits::IdType* merge_partial_packed_offset_start,
645	    typename KTraits::IdType* merge_partial_packed_offset_end,
646	    typename KTraits::IdType* merge_partial_stride, typename KTraits::DTypeO* partial_o,
647	    float* partial_lse, typename KTraits::DTypeO* final_o, float* final_lse,
648	    const uint32_t o_stride_n, const uint32_t o_stride_h, const uint_fastdiv& num_heads,
649	    const bool& return_lse_base_on_e) {
650	  constexpr uint32_t VEC_SIZE = 8;  // partial o has data type float
651	  constexpr uint32_t NUM_THRS_PER_ROW = KTraits::HEAD_DIM_CKV / VEC_SIZE;
652	  constexpr uint32_t ROWS_PER_ITERATION = (KTraits::NUM_THREADS) / NUM_THRS_PER_ROW;
653	  const uint32_t cta_idx = (gridDim.x * blockIdx.y + blockIdx.x);
654	  const uint32_t thread_id = (threadIdx.z * blockDim.y + threadIdx.y) * blockDim.x + threadIdx.x;
655	  const uint32_t offset_start = merge_packed_offset_start[cta_idx];
656	  const uint32_t len = merge_packed_offset_end[cta_idx] - offset_start;
657	  const uint32_t partial_offset_start = merge_partial_packed_offset_start[cta_idx];
658	  const uint32_t partial_offset_end = merge_partial_packed_offset_end[cta_idx];
659	  const uint32_t stride = merge_partial_stride[cta_idx];
660	#pragma unroll 1
661	  for (uint32_t local_packed_offset = thread_id / NUM_THRS_PER_ROW; local_packed_offset < len;
662	       local_packed_offset += ROWS_PER_ITERATION) {
663	    uint32_t final_packed_offset = offset_start + local_packed_offset;
664	    uint32_t q, r;
665	    num_heads.divmod(final_packed_offset, q, r);
666	    state_t<VEC_SIZE> st;
667	#pragma unroll 8
668	    for (uint32_t partial_packed_offset = partial_offset_start + local_packed_offset;
669	         partial_packed_offset < partial_offset_end; partial_packed_offset += stride) {
670	      vec_t<float, VEC_SIZE> o_partial;
671	      float lse_partial;
672	      o_partial.cast_load(partial_o + partial_packed_offset * KTraits::HEAD_DIM_CKV +
673	                          (thread_id % NUM_THRS_PER_ROW) * VEC_SIZE);
674	      lse_partial = partial_lse[partial_packed_offset];
675	      st.merge(o_partial, lse_partial, 1);
676	    }
677	    st.normalize();
678	    st.o.cast_store(final_o +
679	                    (q * o_stride_n + r * o_stride_h + (thread_id % NUM_THRS_PER_ROW) * VEC_SIZE));
680	    if (final_lse) {
681	      final_lse[q * num_heads + r] = st.get_lse();
682	      if (return_lse_base_on_e) {
683	        final_lse[q * num_heads + r] *= math::loge2;
684	      }
685	    }
686	  }
687	}
