689	template <typename KTraits>
690	__device__ __forceinline__ void write_empty_o(typename KTraits::DTypeO* final_o, float* final_lse,
691	                                              typename KTraits::DTypeO* partial_o,
692	                                              float* partial_lse, const uint32_t o_stride_n,
693	                                              const uint32_t o_stride_h, const uint32_t q_len,
694	                                              const uint32_t packed_offset,
695	                                              const uint_fastdiv& num_heads) {
696	  const uint32_t thread_id = (threadIdx.z * blockDim.y + threadIdx.y) * blockDim.x + threadIdx.x;
697	  const uint32_t total_packed = q_len * static_cast<uint32_t>(num_heads);
698	  const uint32_t remaining_packed =
699	      (packed_offset < total_packed) ? total_packed - packed_offset : 0;
700	  const uint32_t num_valid_packed = remaining_packed < static_cast<uint32_t>(KTraits::CTA_TILE_Q)
701	                                        ? remaining_packed
702	                                        : static_cast<uint32_t>(KTraits::CTA_TILE_Q);
703	  const uint32_t num_elems = num_valid_packed * KTraits::HEAD_DIM_CKV;
704	
705	  if (partial_o != nullptr) {
706	    const uint32_t partial_packed_offset = blockIdx.x * KTraits::CTA_TILE_Q;
707	    for (uint32_t elem_idx = thread_id; elem_idx < num_elems; elem_idx += KTraits::NUM_THREADS) {
708	      const uint32_t packed_idx = elem_idx / KTraits::HEAD_DIM_CKV;
709	      const uint32_t dim_idx = elem_idx - packed_idx * KTraits::HEAD_DIM_CKV;
710	      partial_o[(partial_packed_offset + packed_idx) * KTraits::HEAD_DIM_CKV + dim_idx] =
711	          typename KTraits::DTypeO(0.f);
712	    }
713	    for (uint32_t packed_idx = thread_id; packed_idx < num_valid_packed;
714	         packed_idx += KTraits::NUM_THREADS) {
715	      partial_lse[partial_packed_offset + packed_idx] =
716	          -cuda::std::numeric_limits<float>::infinity();
717	    }
718	  } else {
719	    for (uint32_t elem_idx = thread_id; elem_idx < num_elems; elem_idx += KTraits::NUM_THREADS) {
720	      const uint32_t packed_idx = elem_idx / KTraits::HEAD_DIM_CKV;
721	      const uint32_t dim_idx = elem_idx - packed_idx * KTraits::HEAD_DIM_CKV;
722	      uint32_t q, r;
723	      num_heads.divmod(packed_offset + packed_idx, q, r);
724	      final_o[q * o_stride_n + r * o_stride_h + dim_idx] = typename KTraits::DTypeO(0.f);
725	    }
726	    if (final_lse) {
727	      for (uint32_t packed_idx = thread_id; packed_idx < num_valid_packed;
728	           packed_idx += KTraits::NUM_THREADS) {
729	        uint32_t q, r;
730	        num_heads.divmod(packed_offset + packed_idx, q, r);
731	        final_lse[q * num_heads + r] = -cuda::std::numeric_limits<float>::infinity();
732	      }
733	    }
734	  }
735	}
