737	template <typename KTraits>
738	__device__ __forceinline__ void write_o(typename KTraits::SharedStorage* smem_storage,
739	                                        typename KTraits::DTypeO* final_o, float* final_lse,
740	                                        typename KTraits::DTypeO* partial_o, float* partial_lse,
741	                                        float (*o_frag)[8], typename KTraits::DTypeQKAccum* m,
742	                                        float* d, const uint32_t o_stride_n,
743	                                        const uint32_t o_stride_h, const uint32_t q_len,
744	                                        const uint32_t packed_offset, const uint_fastdiv& num_heads,
745	                                        const bool& return_lse_base_on_e) {
746	  using DTypeO = typename KTraits::DTypeO;
747	  constexpr uint32_t NUM_MMA_D_CKV = KTraits::NUM_MMA_D_CKV;
748	  constexpr uint32_t HEAD_DIM_CKV = KTraits::HEAD_DIM_CKV;
749	  constexpr uint32_t UPCAST_STRIDE_FINAL_O = KTraits::UPCAST_STRIDE_FINAL_O;
750	  const uint32_t lane_idx = threadIdx.x, warpgroup_idx = threadIdx.z, warp_idx_in_wg = threadIdx.y;
751	  smem_t<KTraits::SWIZZLE_MODE_O> o_smem(smem_storage->o_smem);
752	#pragma unroll
753	  for (uint32_t mma_d = 0; mma_d < NUM_MMA_D_CKV / 2; ++mma_d) {
754	    uint32_t o_frag_f16[8 / 2];
755	    vec_cast<DTypeO, float>::cast<8>((DTypeO*)o_frag_f16, o_frag[mma_d]);
756	#ifdef FLASHINFER_STMATRIX_M8N8X4_ENABLED
757	    uint32_t o_smem_offset_w = o_smem.template get_permuted_offset<UPCAST_STRIDE_FINAL_O>(
758	        warp_idx_in_wg * 16 + lane_idx % 16,
759	        warpgroup_idx * NUM_MMA_D_CKV + mma_d * 2 + lane_idx / 16);
760	    o_smem.template stmatrix_m8n8x4(o_smem_offset_w, o_frag_f16);
761	#else
762	    uint32_t o_smem_offset_w = o_smem.template get_permuted_offset<UPCAST_STRIDE_FINAL_O>(
763	        warp_idx_in_wg * 16 + lane_idx / 4, warpgroup_idx * NUM_MMA_D_CKV + mma_d * 2);
764	    ((uint32_t*)(o_smem.base + o_smem_offset_w))[lane_idx % 4] = o_frag_f16[0];
765	    ((uint32_t*)(o_smem.base + o_smem_offset_w + 8 * UPCAST_STRIDE_FINAL_O))[lane_idx % 4] =
766	        o_frag_f16[1];
767	    ((uint32_t*)(o_smem.base + (o_smem_offset_w ^ 0x1)))[lane_idx % 4] = o_frag_f16[2];
768	    ((uint32_t*)(o_smem.base + (o_smem_offset_w ^ 0x1) + 8 * UPCAST_STRIDE_FINAL_O))[lane_idx % 4] =
769	        o_frag_f16[3];
770	#endif
771	  }
772	
773	  if (partial_o != nullptr) {
774	    // write to partial_o
775	#pragma unroll
776	    for (uint32_t j = 0; j < 2; ++j) {
777	      uint32_t q_idx = (packed_offset + warp_idx_in_wg * 16 + 8 * j + lane_idx / 4) / num_heads;
778	      if (lane_idx % 4 == 0 && q_idx < q_len) {
779	        float lse = (m[j] == typename KTraits::DTypeQKAccum(-math::inf))
780	                        ? -cuda::std::numeric_limits<float>::infinity()
781	                        : math::ptx_log2(d[j]) + float(m[j]);
782	        partial_lse[(blockIdx.x * 4 + warp_idx_in_wg) * 16 + 8 * j + lane_idx / 4] = lse;
783	      }
784	    }
785	
786	    // step 1. smem to gmem
787	    uint32_t o_smem_offset_w = o_smem.template get_permuted_offset<UPCAST_STRIDE_FINAL_O>(
788	        warp_idx_in_wg * 16 + lane_idx / 8, warpgroup_idx * NUM_MMA_D_CKV + lane_idx % 8);
789	#pragma unroll
790	    for (uint32_t j = 0; j < 4; ++j) {
791	      uint32_t q_idx = (packed_offset + warp_idx_in_wg * 16 + 4 * j + lane_idx / 8) / num_heads;
792	      DTypeO* o_partial_ptr =
793	          partial_o +
794	          ((blockIdx.x * 4 + warp_idx_in_wg) * 16 + 4 * j + lane_idx / 8) * HEAD_DIM_CKV +
795	          warpgroup_idx * (HEAD_DIM_CKV / 2) + (lane_idx % 8) * upcast_size<DTypeO>();
796	#pragma unroll
797	      for (uint32_t mma_d = 0; mma_d < NUM_MMA_D_CKV / 8; ++mma_d) {
798	        if (q_idx < q_len) {
799	          o_smem.template store_128b(o_smem_offset_w, o_partial_ptr);
800	        }
801	        o_partial_ptr += 8 * upcast_size<DTypeO>();
802	        o_smem_offset_w = o_smem.template advance_offset_by_column<8>(o_smem_offset_w, mma_d);
803	      }
804	      o_smem_offset_w =
805	          o_smem.template advance_offset_by_row<4, UPCAST_STRIDE_FINAL_O>(o_smem_offset_w) -
806	          NUM_MMA_D_CKV;
807	    }
808	  } else {
809	    // write to final_o
810	
811	    if (final_lse) {
812	#pragma unroll
813	      for (uint32_t j = 0; j < 2; ++j) {
814	        uint32_t q, r;
815	        num_heads.divmod(packed_offset + warp_idx_in_wg * 16 + 8 * j + lane_idx / 4, q, r);
816	        if (lane_idx % 4 == 0 && q < q_len) {
817	          final_lse[q * num_heads + r] = (m[j] == typename KTraits::DTypeQKAccum(-math::inf))
818	                                             ? -cuda::std::numeric_limits<float>::infinity()
819	                                             : math::ptx_log2(d[j]) + float(m[j]);
820	          if (return_lse_base_on_e) {
821	            final_lse[q * num_heads + r] *= math::loge2;
822	          }
823	        }
824	      }
825	    }
826	
827	    // step 1. smem to gmem
828	    uint32_t o_smem_offset_w = o_smem.template get_permuted_offset<UPCAST_STRIDE_FINAL_O>(
829	        warp_idx_in_wg * 16 + lane_idx / 8, warpgroup_idx * NUM_MMA_D_CKV + lane_idx % 8);
830	#pragma unroll
831	    for (uint32_t j = 0; j < 4; ++j) {
832	      uint32_t q, r;
833	      num_heads.divmod(packed_offset + warp_idx_in_wg * 16 + 4 * j + lane_idx / 8, q, r);
834	      DTypeO* o_final_ptr = final_o + q * o_stride_n + r * o_stride_h +
835	                            warpgroup_idx * (HEAD_DIM_CKV / 2) +
836	                            (lane_idx % 8) * upcast_size<DTypeO>();
837	#pragma unroll
838	      for (uint32_t mma_d = 0; mma_d < NUM_MMA_D_CKV / 8; ++mma_d) {
839	        if (q < q_len) {
840	          o_smem.template store_128b(o_smem_offset_w, o_final_ptr);
841	        }
842	        o_final_ptr += 8 * upcast_size<DTypeO>();
843	        o_smem_offset_w = o_smem.template advance_offset_by_column<8>(o_smem_offset_w, mma_d);
844	      }
845	      o_smem_offset_w =
846	          o_smem.template advance_offset_by_row<4, UPCAST_STRIDE_FINAL_O>(o_smem_offset_w) -
847	          NUM_MMA_D_CKV;
848	    }
849	  }
850	}
