852	template <typename KTraits, typename Params>
853	__global__ __launch_bounds__(KTraits::NUM_THREADS) void BatchMLAPagedAttentionKernel(
854	    const __grid_constant__ Params params) {
855	  using DTypeQ = typename Params::DTypeQ;
856	  using DTypeKV = typename Params::DTypeKV;
857	  using DTypeO = typename Params::DTypeO;
858	  using IdType = typename Params::IdType;
859	
860	  extern __shared__ __align__(alignof(typename KTraits::SharedStorage)) uint8_t smem[];
861	  auto& smem_storage = reinterpret_cast<typename KTraits::SharedStorage&>(smem);
862	
863	  typename KTraits::AttentionVariant variant(params, blockIdx.y, smem);
864	
865	  [[maybe_unused]] constexpr SwizzleMode SWIZZLE_MODE_Q_NOPE = KTraits::SWIZZLE_MODE_Q_NOPE;
866	  [[maybe_unused]] constexpr SwizzleMode SWIZZLE_MODE_Q_PE = KTraits::SWIZZLE_MODE_Q_PE;
867	  [[maybe_unused]] constexpr SwizzleMode SWIZZLE_MODE_CKV = KTraits::SWIZZLE_MODE_CKV;
868	  [[maybe_unused]] constexpr SwizzleMode SWIZZLE_MODE_KPE = KTraits::SWIZZLE_MODE_KPE;
869	  [[maybe_unused]] constexpr uint32_t NUM_MMA_KV = KTraits::NUM_MMA_KV;
870	  [[maybe_unused]] constexpr uint32_t NUM_MMA_D_CKV = KTraits::NUM_MMA_D_CKV;
871	  [[maybe_unused]] constexpr uint32_t CTA_TILE_Q = KTraits::CTA_TILE_Q;
872	  [[maybe_unused]] constexpr uint32_t CTA_TILE_KV = KTraits::CTA_TILE_KV;
873	  [[maybe_unused]] constexpr int32_t NUM_STAGES = KTraits::NUM_STAGES;
874	  [[maybe_unused]] constexpr bool CAUSAL = KTraits::CAUSAL;
875	
876	  DTypeQ* q_nope = params.q_nope;
877	  DTypeQ* q_pe = params.q_pe;
878	  DTypeKV* ckv = params.ckv;
879	  DTypeKV* kpe = params.kpe;
880	  IdType* kv_indices = params.kv_indices;
881	  DTypeO* partial_o = params.partial_o;
882	  float* partial_lse = params.partial_lse;
883	  DTypeO* final_o = params.final_o;
884	  float* final_lse = params.final_lse;
885	  IdType* work_indptr = params.work_indptr;
886	
887	  float s_frag[KTraits::QK_SHARD ? NUM_MMA_KV / 2 : NUM_MMA_KV][8];
888	  alignas(16) float o_frag[NUM_MMA_D_CKV / 2][8];
889	  float m[2];
890	  float d[2];
891	
892	  const uint_fastdiv& num_heads = params.num_heads;
893	  const uint_fastdiv& block_size = params.block_size;
894	  const uint32_t q_nope_stride_n = params.q_nope_stride_n;
895	  const uint32_t q_nope_stride_h = params.q_nope_stride_h;
896	  const uint32_t q_pe_stride_n = params.q_pe_stride_n;
897	  const uint32_t q_pe_stride_h = params.q_pe_stride_h;
898	  const uint32_t ckv_stride_page = params.ckv_stride_page;
899	  const uint32_t ckv_stride_n = params.ckv_stride_n;
900	  const uint32_t kpe_stride_page = params.kpe_stride_page;
901	  const uint32_t kpe_stride_n = params.kpe_stride_n;
902	  const uint32_t o_stride_n = params.o_stride_n;
903	  const uint32_t o_stride_h = params.o_stride_h;
904	  const uint32_t cluster_tile_q = gridDim.x * KTraits::CTA_TILE_Q;
905	
906	#pragma unroll 1
907	  for (IdType work_idx = work_indptr[blockIdx.y]; work_idx < work_indptr[blockIdx.y + 1];
908	       ++work_idx) {
909	    const uint32_t q_indptr = params.q_indptr[work_idx];
910	    const uint32_t kv_indptr = params.kv_indptr[work_idx];
911	    const int32_t partial_indptr = params.partial_indptr[work_idx];
912	    const uint32_t q_len = params.q_len[work_idx];
913	    const uint32_t kv_len = params.kv_len[work_idx];
914	    const uint32_t packed_qo_start = params.q_start[work_idx];
915	    const uint32_t kv_start = params.kv_start[work_idx];
916	    const uint32_t kv_end = params.kv_end[work_idx];
917	
918	    const uint32_t qo_packed_idx_base = packed_qo_start + blockIdx.x * KTraits::CTA_TILE_Q;
919	    const uint32_t qo_upperbound =
920	        min(q_len, ceil_div(qo_packed_idx_base + KTraits::CTA_TILE_Q, num_heads));
921	
922	    init_states_<KTraits>(o_frag, m, d);
923	
924	    __syncthreads();
925	    load_q<KTraits>(&smem_storage, q_nope + q_indptr * q_nope_stride_n,
926	                    q_pe + q_indptr * q_pe_stride_n, q_nope_stride_n, q_nope_stride_h,
927	                    q_pe_stride_n, q_pe_stride_h, qo_upperbound, qo_packed_idx_base,
928	                    params.num_heads);
929	
930	    if (kv_end <= kv_start) {
931	      cp_async::commit_group();
932	      cp_async::wait_group<0>();
933	      __syncthreads();
934	      write_empty_o<KTraits>(
935	          final_o + q_indptr * o_stride_n, final_lse ? final_lse + q_indptr * num_heads : nullptr,
936	          (partial_indptr == -1) ? nullptr : partial_o + partial_indptr * KTraits::HEAD_DIM_CKV,
937	          (partial_indptr == -1) ? nullptr : partial_lse + partial_indptr, o_stride_n, o_stride_h,
938	          qo_upperbound, qo_packed_idx_base, num_heads);
939	      continue;
940	    }
941	
942	    int kv_tile_idx =
943	        ceil_div(
944	            (CAUSAL ? min(kv_end, kv_len - q_len + (packed_qo_start + cluster_tile_q) / num_heads)
945	                    : kv_end),
946	            CTA_TILE_KV) -
947	        1 - (kv_start / CTA_TILE_KV);
948	
949	    int mask_tile_idx =
950	        (CAUSAL ? min(kv_end, kv_len - q_len + packed_qo_start / num_heads) : kv_end) /
951	            CTA_TILE_KV -
952	        (kv_start / CTA_TILE_KV);
953	
954	    uint32_t block_iter_base = kv_indptr * block_size + kv_start;
955	    // last kv tile
956	    __syncthreads();
957	    uint32_t packed_kv_bound = kv_indptr * block_size + kv_len;
958	    load_kv<KTraits>(&smem_storage, ckv, kpe, kv_indices, ckv_stride_n, ckv_stride_page,
959	                     kpe_stride_n, kpe_stride_page, packed_kv_bound,
960	                     block_iter_base + kv_tile_idx * CTA_TILE_KV, block_size,
961	                     kv_tile_idx % NUM_STAGES);
962	    cp_async::commit_group();
963	#pragma unroll
964	    for (int stage_idx = 1; stage_idx < NUM_STAGES; ++stage_idx) {
965	      if (kv_tile_idx - stage_idx >= 0) {
966	        load_kv<KTraits>(&smem_storage, ckv, kpe, kv_indices, ckv_stride_n, ckv_stride_page,
967	                         kpe_stride_n, kpe_stride_page, packed_kv_bound,
968	                         block_iter_base + (kv_tile_idx - stage_idx) * CTA_TILE_KV, block_size,
969	                         (kv_tile_idx - stage_idx) % NUM_STAGES);
970	        cp_async::commit_group();
971	      }
972	    }
973	
974	    // loop with mask
975	#pragma unroll 1
976	    for (; kv_tile_idx >= mask_tile_idx && kv_tile_idx > 0; --kv_tile_idx) {
977	      cp_async::wait_group<NUM_STAGES - 1>();
978	      __syncthreads();
979	
980	      // compute mla qk
981	      compute_mla_qk<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, s_frag);
982	
983	      // logits mask
984	      logits_mask_<KTraits>(qo_packed_idx_base, kv_start + kv_tile_idx * CTA_TILE_KV, q_len, kv_len,
985	                            kv_end, num_heads, s_frag);
986	
987	      // compute m,d states in online softmax
988	      update_mdo_states_<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, variant, s_frag, o_frag,
989	                                  m, d);
990	
991	      // compute sfm * v
992	      compute_mla_pv<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, s_frag, d, o_frag);
993	
994	      if (kv_tile_idx - NUM_STAGES >= 0) {
995	        __syncthreads();
996	        load_kv<KTraits>(&smem_storage, ckv, kpe, kv_indices, ckv_stride_n, ckv_stride_page,
997	                         kpe_stride_n, kpe_stride_page, packed_kv_bound,
998	                         block_iter_base + (kv_tile_idx - NUM_STAGES) * CTA_TILE_KV, block_size,
999	                         (kv_tile_idx - NUM_STAGES) % NUM_STAGES);
1000	        cp_async::commit_group();
1001	      }
1002	    }
1003	
1004	    // loop without mask
1005	#pragma unroll 1
1006	    for (; kv_tile_idx + 1 > NUM_STAGES; --kv_tile_idx) {
1007	      cp_async::wait_group<NUM_STAGES - 1>();
1008	      __syncthreads();
1009	
1010	      // compute mla qk
1011	      compute_mla_qk<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, s_frag);
1012	
1013	      // compute m,d states in online softmax
1014	      update_mdo_states_<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, variant, s_frag, o_frag,
1015	                                  m, d);
1016	      // compute sfm * v
1017	      compute_mla_pv<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, s_frag, d, o_frag);
1018	
1019	      __syncthreads();
1020	      load_kv<KTraits>(&smem_storage, ckv, kpe, kv_indices, ckv_stride_n, ckv_stride_page,
1021	                       kpe_stride_n, kpe_stride_page, packed_kv_bound,
1022	                       block_iter_base + (kv_tile_idx - NUM_STAGES) * CTA_TILE_KV, block_size,
1023	                       (kv_tile_idx - NUM_STAGES) % NUM_STAGES);
1024	      cp_async::commit_group();
1025	    }
1026	    cp_async::wait_group<0>();
1027	    __syncthreads();
1028	
1029	    // last tiles
1030	#pragma unroll
1031	    for (; kv_tile_idx >= 0; --kv_tile_idx) {
1032	      // compute mla qk
1033	      compute_mla_qk<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, s_frag);
1034	
1035	      logits_mask_<KTraits>(qo_packed_idx_base, kv_start + kv_tile_idx * CTA_TILE_KV, q_len, kv_len,
1036	                            kv_end, num_heads, s_frag);
1037	
1038	      // compute m,d states in online softmax
1039	      update_mdo_states_<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, variant, s_frag, o_frag,
1040	                                  m, d);
1041	
1042	      // compute sfm * v
1043	      compute_mla_pv<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, s_frag, d, o_frag);
1044	    }
1045	
1046	    __syncthreads();
1047	
1048	    // normalize and write back
1049	    normalize_d_<KTraits>(&smem_storage, kv_tile_idx % NUM_STAGES, o_frag, m, d);
1050	
1051	    finalize_m_<KTraits>(variant, m);
1052	
1053	    write_o<KTraits>(
1054	        &smem_storage, final_o + q_indptr * o_stride_n,
1055	        final_lse ? final_lse + q_indptr * num_heads : nullptr,
1056	        (partial_indptr == -1) ? nullptr : partial_o + partial_indptr * KTraits::HEAD_DIM_CKV,
1057	        (partial_indptr == -1) ? nullptr : partial_lse + partial_indptr, o_frag, m, d, o_stride_n,
1058	        o_stride_h, qo_upperbound, qo_packed_idx_base, num_heads, params.return_lse_base_on_e);
1059	  }
1060	
1061	  auto grid = cg::this_grid();
1062	  grid.sync();
1063	
1064	  // the second stage, merge partial outputs
1065	  DevicePersistentMergeStates<KTraits>(
1066	      params.merge_packed_offset_start, params.merge_packed_offset_end,
1067	      params.merge_partial_packed_offset_start, params.merge_partial_packed_offset_end,
1068	      params.merge_partial_stride, partial_o, partial_lse, final_o, final_lse, o_stride_n,
1069	      o_stride_h, num_heads, params.return_lse_base_on_e);
1070	}
