1072	#define DISPATCH_SMEM_CONFIG(smem_limit_per_sm, NUM_STAGES, CTA_TILE_KV, QK_SHARD, ...) \
1073	  if (smem_limit_per_sm >= 221696) {                                                    \
1074	    constexpr uint32_t NUM_STAGES = 2;                                                  \
1075	    constexpr uint32_t CTA_TILE_KV = 64;                                                \
1076	    constexpr bool QK_SHARD = true;                                                     \
1077	    __VA_ARGS__;                                                                        \
1078	  } else if (smem_limit_per_sm >= 147968) {                                             \
1079	    constexpr uint32_t NUM_STAGES = 2;                                                  \
1080	    constexpr uint32_t CTA_TILE_KV = 32;                                                \
1081	    constexpr bool QK_SHARD = true;                                                     \
1082	    __VA_ARGS__;                                                                        \
1083	  } else if (smem_limit_per_sm >= 92672) {                                              \
1084	    constexpr uint32_t NUM_STAGES = 1;                                                  \
1085	    constexpr uint32_t CTA_TILE_KV = 16;                                                \
1086	    constexpr bool QK_SHARD = false;                                                    \
1087	    __VA_ARGS__;                                                                        \
1088	  } else {                                                                              \
1089	    std::ostringstream err;                                                             \
1090	    err << "Unsupported shared memory size: " << smem_limit_per_sm;                     \
1091	    FLASHINFER_ERROR(err.str());                                                        \
1092	    return cudaErrorNotSupported;                                                       \
1093	  }
