1095	template <MaskMode MASK_MODE, uint32_t HEAD_DIM_CKV, uint32_t HEAD_DIM_KPE, typename Params>
1096	cudaError_t BatchMLAPagedAttention(Params params, uint32_t num_blks_x, uint32_t num_blks_y,
1097	                                   cudaStream_t stream) {
1098	  using DTypeQ = typename Params::DTypeQ;
1099	  using DTypeKV = typename Params::DTypeKV;
1100	  using DTypeO = typename Params::DTypeO;
1101	  using IdType = typename Params::IdType;
1102	  if (MASK_MODE == MaskMode::kCustom) {
1103	    return cudaErrorNotSupported;
1104	  }
1105	  constexpr bool CAUSAL = MASK_MODE == MaskMode::kCausal;
1106	
1107	  dim3 nblks(num_blks_x, num_blks_y);
1108	  dim3 nthrs(32, 4, 2);
1109	
1110	  // get GPU shared memory size
1111	  int device;
1112	  int smem_limit_per_sm;
1113	  cudaGetDevice(&device);
1114	  cudaDeviceGetAttribute(&smem_limit_per_sm, cudaDevAttrMaxSharedMemoryPerMultiprocessor, device);
1115	
1116	  DISPATCH_SMEM_CONFIG(smem_limit_per_sm, NUM_STAGES, CTA_TILE_KV, QK_SHARD, {
1117	    using KTraits = KernelTraits<CAUSAL, NUM_STAGES, QK_SHARD, HEAD_DIM_CKV, HEAD_DIM_KPE,
1118	                                 /*CTA_TILE_Q_=*/64, CTA_TILE_KV, DTypeQ, DTypeKV, DTypeO, IdType>;
1119	    size_t smem_size = sizeof(typename KTraits::SharedStorage);
1120	    auto kernel = BatchMLAPagedAttentionKernel<KTraits, Params>;
1121	    void* args[] = {(void*)&params};
1122	
1123	    FLASHINFER_CUDA_CALL(
1124	        cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
1125	    FLASHINFER_CUDA_CALL(
1126	        cudaLaunchCooperativeKernel((void*)kernel, nblks, nthrs, args, smem_size, stream));
1127	  });
1128	
1129	  return cudaSuccess;
1130	}
1131	
1132	}  // namespace mla
1133	
1134	}  // namespace flashinfer
